import React, { useState } from "react";

export default function LeftPanel() {
  const [isOpen, setIsOpen] = useState(true);

  return (
    <div className="h-100" style={{ width: "350px", position: "relative" }}>
      {/* 1. Barre de recherche (En dehors/au-dessus du bloc blanc) */}
      <div className="d-flex mb-2" style={{ height: "40px" }}>
        <div
          className="d-flex align-items-center justify-content-center text-white"
          style={{ width: "45px", backgroundColor: "#f09c13" }}
        >
          🔍
        </div>
        <input
          type="text"
          className="form-control rounded-0 border-0 fw-bold"
          defaultValue="Raysquad#2902"
          style={{ backgroundColor: "#e9ecef", color: "#333" }}
        />
      </div>

      {/* BLOC BLANC PRINCIPAL */}
      <div className="bg-white h-100 shadow-sm">
        {/* 2. Bannière et Photo de profil superposée */}
        <div className="position-relative mb-5">
          <div
            style={{
              height: "120px",
              backgroundImage: "url(https://via.placeholder.com/350x120)",
              backgroundSize: "cover",
            }}
          ></div>

          {/* PP à droite, à moitié en dehors verticalement et horizontalement */}
          <div
            className="position-absolute d-flex align-items-center"
            style={{ bottom: "-40px", right: "-20px", zIndex: 10 }}
          >
            <div className="bg-white p-1 shadow">
              <img
                src="https://via.placeholder.com/80"
                alt="Avatar"
                style={{ width: "80px", height: "80px", display: "block" }}
              />
            </div>
            {/* Pseudo à droite de la PP, complètement en dehors du bloc blanc */}
            <div
              className="ms-2 bg-white px-3 py-1 fw-bold fs-5 shadow-sm"
              style={{ whiteSpace: "nowrap" }}
            >
              Raysquad
            </div>
          </div>
        </div>

        {/* 3. Info Héros Sélectionné */}
        <div className="d-flex align-items-center mb-3 px-3 mt-5">
          <div
            className="border border-warning border-2 me-3"
            style={{ width: "70px", height: "70px" }}
          >
            <img
              src="https://via.placeholder.com/70"
              alt="Cassidy"
              className="w-100 h-100 object-fit-cover"
            />
          </div>
          <div>
            <div
              className="text-warning fw-bold text-uppercase"
              style={{ fontSize: "0.8rem" }}
            >
              Damage
            </div>
            <div
              className="fw-bold fs-3 text-uppercase"
              style={{ lineHeight: "1" }}
            >
              CASSIDY
            </div>
          </div>
        </div>

        {/* 4. Grille de sélection PLIABLE */}
        <div className="px-3">
          <button
            onClick={() => setIsOpen(!isOpen)}
            className="btn w-100 d-flex justify-content-between align-items-center rounded-0 fw-bold mb-1"
            style={{ backgroundColor: "#cdd3d8", color: "#333" }}
          >
            SELECT HERO
            <span>{isOpen ? "▲" : "▼"}</span>
          </button>

          {isOpen && (
            <div
              className="d-flex flex-wrap border p-1 bg-light"
              style={{ gap: "4px" }}
            >
              {Array.from({ length: 12 }).map((_, i) => (
                <div
                  key={i}
                  className="bg-white border"
                  style={{ width: "calc(25% - 3px)", aspectRatio: "1/1" }}
                >
                  <img
                    src="https://via.placeholder.com/50"
                    alt="hero"
                    className="w-100 h-100"
                  />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* 5. Rang */}
        <div className="d-flex align-items-center px-3 mt-4 pb-4">
          <div
            className="rounded-circle border border-warning border-4 d-flex justify-content-center align-items-center fw-bold fs-3 me-3"
            style={{ width: "70px", height: "70px", color: "#f09c13" }}
          >
            88
          </div>
          <div>
            <div className="text-muted fw-bold" style={{ fontSize: "0.7rem" }}>
              OVERALL
            </div>
            <div className="fw-bold fs-4 text-uppercase">MASTER</div>
          </div>
        </div>
      </div>
    </div>
  );
}
